t.script:
            document.addEventListener('DOMContentLoaded', function() {

                const proyectoId = ;
                const csrfToken  = '';

                const inputBuscar     = document.getElementById('inputBuscarMiembro');
                const divResultados   = document.getElementById('resultadosMiembros');
                const btnConfirmar    = document.getElementById('btnConfirmarMiembro');
                const divNuevo        = document.getElementById('divNuevoMiembro');
                const msgExito        = document.getElementById('msg-miembro-exito');
                const msgError        = document.getElementById('msg-miembro-error');

                let partnerId   = null;   // ID del partner seleccionado (null = crear nuevo)
                let nombreNuevo = null;   // Nombre para crear si no existe

                // ── Busqueda con debounce ──────────────────────────────
                let debounceTimer;
                inputBuscar.addEventListener('input', function() {
                    clearTimeout(debounceTimer);
                    const term = this.value.trim();
                    partnerId   = null;
                    nombreNuevo = null;
                    btnConfirmar.disabled = true;
                    divResultados.innerHTML = '';
                    divNuevo.classList.add('d-none');

                    if (term.length < 2) return;

                    debounceTimer = setTimeout(function() {
                        fetch('/digitalizacion/api/buscar_partner', {
                            method: 'POST',
                            headers: {
                                'Content-Type': 'application/json',
                                'X-CSRFToken': csrfToken
                            },
                            body: JSON.stringify({
                                jsonrpc: '2.0', method: 'call', id: 1,
                                params: { term: term, proyecto_id: proyectoId }
                            })
                        })
                        .then(r => r.json())
                        .then(data => {
                            const partners = (data.result || {}).partners || [];
                            divResultados.innerHTML = '';

                            if (partners.length === 0) {
                                // Permitir crear nuevo
                                nombreNuevo = term;
                                divNuevo.classList.remove('d-none');
                                btnConfirmar.disabled = false;
                            } else {
                                partners.forEach(p => {
                                    const item = document.createElement('button');
                                    item.type = 'button';
                                    item.className = 'list-group-item list-group-item-action';
                                    item.textContent = p.name + (p.email ? ' (' + p.email + ')' : '');
                                    item.addEventListener('click', function() {
                                        partnerId   = p.id;
                                        nombreNuevo = null;
                                        inputBuscar.value = p.name;
                                        divResultados.innerHTML = '';
                                        divNuevo.classList.add('d-none');
                                        btnConfirmar.disabled = false;
                                    });
                                    divResultados.appendChild(item);
                                });
                            }
                        })
                        .catch(() => {
                            divResultados.innerHTML = '
Error al buscar contactos.';
                        });
                    }, 350);
                });

                // ── Confirmar agregar miembro ──────────────────────────
                btnConfirmar.addEventListener('click', function() {
                    btnConfirmar.disabled = true;
                    const payload = {
                        jsonrpc: '2.0', method: 'call', id: 1,
                        params: {
                            proyecto_id: proyectoId,
                            partner_id:  partnerId   || null,
                            nombre_nuevo: nombreNuevo || null
                        }
                    };

                    fetch('/digitalizacion/api/agregar_miembro', {
                        method: 'POST',
                        headers: {
                            'Content-Type': 'application/json',
                            'X-CSRFToken': csrfToken
                        },
                        body: JSON.stringify(payload)
                    })
                    .then(r => r.json())
                    .then(data => {
                        const result = data.result || {};
                        // Cerrar modal
                        bootstrap.Modal.getInstance(
                            document.getElementById('modalAgregarMiembro')
                        ).hide();

                        if (result.status === 'success') {
                            msgExito.classList.remove('d-none');
                            msgError.classList.add('d-none');
                            // Recargar la pagina para mostrar el nuevo miembro en la tabla
                            setTimeout(() => location.reload(), 800);
                        } else {
                            msgError.textContent = result.message || 'Error al agregar miembro.';
                            msgError.classList.remove('d-none');
                            msgExito.classList.add('d-none');
                            btnConfirmar.disabled = false;
                        }
                    })
                    .catch(() => {
                        msgError.textContent = 'Error de conexion al servidor.';
                        msgError.classList.remove('d-none');
                        btnConfirmar.disabled = false;
                    });
                });

                // Limpiar al cerrar el modal
                document.getElementById('modalAgregarMiembro').addEventListener('hidden.bs.modal', function() {
                    inputBuscar.value   = '';
                    divResultados.innerHTML = '';
                    divNuevo.classList.add('d-none');
                    btnConfirmar.disabled = true;
                    partnerId   = null;
                    nombreNuevo = null;
                });
            });
